import numpy as np

class ModelCheckpoint:
    def __init__(self, mode: str = 'min'):
        if mode not in ('min', 'max'):
            raise ValueError(f"mode must be 'min' or 'max', got '{mode}'")
        self.mode = mode
        self.best_metric = float('inf') if mode == 'min' else float('-inf')
        self.best_weights = None
        self.n_saves = 0

    def update(self, metric: float, weights: dict) -> bool:
        improved = (metric < self.best_metric) if self.mode == 'min' else (metric > self.best_metric)
        if improved:
            self.best_metric = metric
            self.best_weights = {k: v.copy() for k, v in weights.items()}
            self.n_saves += 1
            return True
        return False

    def restore(self) -> dict:
        if self.best_weights is None:
            raise RuntimeError('No checkpoint saved yet')
        return {k: v.copy() for k, v in self.best_weights.items()}
